# Purpose: Load TPC-H data at scale factor 30 (SF30 ~ 30 GB) into the tpch database
#          using the cpimport bulk loader for MariaDB ColumnStore.
#          Files are pipe-delimited .tbl files generated by dbgen.

cpimport tpch nation    /data/tpch/SF30/nation.tbl
cpimport tpch region    /data/tpch/SF30/region.tbl
cpimport tpch part      /data/tpch/SF30/part.tbl
cpimport tpch supplier  /data/tpch/SF30/supplier.tbl
cpimport tpch partsupp  /data/tpch/SF30/partsupp.tbl
cpimport tpch customer  /data/tpch/SF30/customer.tbl
cpimport tpch orders    /data/tpch/SF30/orders.tbl
cpimport tpch lineitem  /data/tpch/SF30/lineitem.tbl
